/**
 * WorldTravelScene — Main travel scene with parallax scrolling,
 * caravan movement, day/night cycle, region transitions, and encounters.
 *
 * PixiJS handles the game world rendering (parallax layers, caravan sprites).
 * All HUD and dialog overlays are HTML/CSS in #ui-root.
 *
 * @module WorldTravelScene
 */

import { Container, Graphics } from 'pixi.js';
import debugLog from '../debug/DebugLog.js';
import sceneManager from '../core/SceneManager.js';
import eventBus from '../core/EventBus.js';
import focusManager from '../input/FocusManager.js';
import inputManager from '../input/InputManager.js';
import ParallaxRenderer from '../renderer/ParallaxRenderer.js';
import travelSystem from '../systems/TravelSystem.js';
import dataStore from '../systems/DataLoader.js';

