/** Default palette if biome not found. */
const DEFAULT_PALETTE = BIOME_PALETTES.temperate_forest;

/** Tile width for seamless scrolling layers. */
const TILE_WIDTH = 1600;

/** Ground height as fraction of viewport. */
const GROUND_FRACTION = 0.30;

/** Path height in pixels. */
const PATH_HEIGHT = 40;

export default class WorldTravelScene {
  constructor() {
    this.container = new Container();

    /** @type {ParallaxRenderer|null} */
    this._parallax = null;

    /** @type {HTMLElement|null} */
    this._hudEl = null;

    /** @type {HTMLElement|null} */
    this._dialogEl = null;

    /** Camera X position (world units). */
    this._cameraX = 0;

    /** Viewport dimensions. */
    this._width = 800;
    this._height = 600;

    /** Current biome palette. */
    this._palette = DEFAULT_PALETTE;

    /** Caravan graphics container. */
    this._caravanContainer = null;

    /** Event listener references for cleanup. */
    this._eventHandlers = {};
  }

  async init() {
    debugLog.info('WorldTravelScene: init');
  }

  async enter(data) {
    debugLog.event('WorldTravelScene: enter');

    // Get viewport dimensions
    const canvas = document.getElementById('game-canvas');
    if (canvas) {
      this._width = canvas.clientWidth || 800;
      this._height = canvas.clientHeight || 600;
    }

    // Determine starting region
    let startRegion = 'greenhollow';
    if (data && data.regionId) {
      startRegion = data.regionId;
    }

    // Use party from data or from debug
    const party = (data && data.party) || window.__debug?.party || null;

    // Initialize travel system
    travelSystem.init(startRegion, party);

    // Set palette from biome
    const region = travelSystem.currentRegion;
    if (region) {
      this._palette = BIOME_PALETTES[region.biome] || DEFAULT_PALETTE;
    }

    // Build parallax layers
    this._buildParallax();

    // Build caravan visuals
    this._buildCaravan();

    // Build HUD (HTML/CSS)
    this._buildHUD();

    // Subscribe to travel events
    this._subscribeEvents();

    // Register debug commands
    this._registerDebugCommands();

    // Update HUD with initial state
    this._updateHUD();

    // Expose for testing
    if (window.__debug) {
      window.__debug.travelSystem = travelSystem;
      window.__debug.worldTravelScene = this;
    }
  }

  exit() {
    debugLog.event('WorldTravelScene: exit');

    // Unsubscribe events
    this._unsubscribeEvents();

    // Remove HUD
    if (this._hudEl && this._hudEl.parentNode) {
      this._hudEl.parentNode.removeChild(this._hudEl);
    }
    this._hudEl = null;

    // Remove dialog
    this._dismissDialog();

    // Clean up parallax
    if (this._parallax) {
      this._parallax.destroy();
      this._parallax = null;
    }

    // Clean up caravan
    if (this._caravanContainer) {
      if (this._caravanContainer.parent) {
        this._caravanContainer.parent.removeChild(this._caravanContainer);
      }
      this._caravanContainer.destroy({ children: true });
      this._caravanContainer = null;
    }

    focusManager.clear();
  }

  // ── Parallax Setup ──────────────────────────────────

  _buildParallax() {
    this._parallax = new ParallaxRenderer();
    this._parallax.resize(this._width, this._height);

    const w = TILE_WIDTH;
    const h = this._height;
    const groundY = h * (1 - GROUND_FRACTION);

    // Layer 1: Sky (static, no scroll)
    const skyContainer = new Container();
    const sky = new Graphics();
    // Gradient effect using two rectangles
    sky.rect(0, 0, w * 2, groundY * 0.5);
    sky.fill(this._palette.sky[0]);
    sky.rect(0, groundY * 0.5, w * 2, groundY * 0.5);
    sky.fill(this._palette.sky[1]);
    skyContainer.addChild(sky);

    // Add some clouds
    const clouds = new Graphics();
    for (let i = 0; i < 8; i++) {
      const cx = (i * w * 2 / 8) + Math.random() * 100;
      const cy = 30 + Math.random() * (groundY * 0.3);
      const cw = 60 + Math.random() * 80;
      const ch = 15 + Math.random() * 15;
      clouds.ellipse(cx, cy, cw, ch);
      clouds.fill({ color: this._palette.clouds, alpha: 0.3 + Math.random() * 0.2 });
    }
    skyContainer.addChild(clouds);

    this._parallax.addLayer('sky', 0.05, skyContainer, { width: w * 2, tiled: true });

    // Layer 2: Mountains (mid-ground, slow scroll)
    const mtContainer = new Container();
    const mountains = new Graphics();

    // Draw mountain silhouettes
    for (let tile = 0; tile < 2; tile++) {
      const ox = tile * w;
      for (let i = 0; i < 5; i++) {
        const mx = ox + i * (w / 4) + Math.random() * 80 - 40;
        const mw = 200 + Math.random() * 200;
        const mh = 80 + Math.random() * 120;
        const my = groundY - 20;

        mountains.moveTo(mx - mw / 2, my);
        mountains.lineTo(mx, my - mh);
        mountains.lineTo(mx + mw / 2, my);
        mountains.closePath();
        mountains.fill(this._palette.mountains[i % 2]);
      }
    }
    mtContainer.addChild(mountains);

    this._parallax.addLayer('mountains', 0.2, mtContainer, { width: w * 2, tiled: true });

    // Layer 3: Trees (mid-near, moderate scroll)
    const treeContainer = new Container();
    const trees = new Graphics();

    for (let tile = 0; tile < 2; tile++) {
      const ox = tile * w;
      for (let i = 0; i < 12; i++) {
        const tx = ox + i * (w / 6) + Math.random() * 60 - 30;
        const ty = groundY - 5;
        const tw = 20 + Math.random() * 20;
        const th = 40 + Math.random() * 60;
        const colorIdx = Math.floor(Math.random() * this._palette.trees.length);

        // Trunk
        trees.rect(tx - 4, ty - th * 0.3, 8, th * 0.3);
        trees.fill(0x553322);

        // Canopy (triangle)
        trees.moveTo(tx - tw, ty - th * 0.3);
        trees.lineTo(tx, ty - th);
        trees.lineTo(tx + tw, ty - th * 0.3);
        trees.closePath();
        trees.fill(this._palette.trees[colorIdx]);
      }
    }
    treeContainer.addChild(trees);

    this._parallax.addLayer('trees', 0.5, treeContainer, { width: w * 2, tiled: true });

    // Layer 4: Ground (near, full scroll)
    const groundContainer = new Container();
    const ground = new Graphics();

    for (let tile = 0; tile < 2; tile++) {
      const ox = tile * w;

      // Main ground
      ground.rect(ox, groundY, w, h - groundY);
      ground.fill(this._palette.ground);

      // Path/road
      const pathY = groundY + (h - groundY) * 0.35;
      ground.rect(ox, pathY - PATH_HEIGHT / 2, w, PATH_HEIGHT);
      ground.fill(this._palette.path);

      // Path edges
      ground.rect(ox, pathY - PATH_HEIGHT / 2 - 2, w, 2);
      ground.fill({ color: 0x000000, alpha: 0.15 });
      ground.rect(ox, pathY + PATH_HEIGHT / 2, w, 2);
      ground.fill({ color: 0x000000, alpha: 0.15 });

      // Grass tufts
      for (let g = 0; g < 20; g++) {
        const gx = ox + Math.random() * w;
        const gy = groundY + Math.random() * (h - groundY);
        // Skip if on path
        if (gy > pathY - PATH_HEIGHT / 2 - 5 && gy < pathY + PATH_HEIGHT / 2 + 5) continue;

        ground.moveTo(gx - 3, gy);
        ground.lineTo(gx, gy - 8 - Math.random() * 6);
        ground.lineTo(gx + 3, gy);
        ground.closePath();
        ground.fill(this._palette.grass);
      }
    }
    groundContainer.addChild(ground);

    this._parallax.addLayer('ground', 1.0, groundContainer, { width: w * 2, tiled: true });

    // Add parallax root to scene container
    this.container.addChild(this._parallax.root);
  }

  // ── Caravan Setup ───────────────────────────────────

  _buildCaravan() {
    this._caravanContainer = new Container();

    const groundY = this._height * (1 - GROUND_FRACTION);
    const pathY = groundY + (this._height - groundY) * 0.35;

    // Wagon body
    const wagon = new Graphics();
    wagon.rect(-30, -30, 60, 25);
    wagon.fill(0x8b5a2b);
    // Wagon roof
    wagon.moveTo(-32, -30);
    wagon.lineTo(0, -50);
    wagon.lineTo(32, -30);
    wagon.closePath();
    wagon.fill(0x664422);
    // Wheels
    wagon.circle(-18, -2, 8);
    wagon.fill(0x443322);
    wagon.circle(18, -2, 8);
    wagon.fill(0x443322);
    // Wheel spokes
    wagon.circle(-18, -2, 3);
    wagon.fill(0x665544);
    wagon.circle(18, -2, 3);
    wagon.fill(0x665544);

    this._caravanContainer.addChild(wagon);

    // Party member figure(s) walking beside the wagon
    const party = travelSystem.party;
    const memberCount = party ? Math.min(party.members.length, 4) : 1;

    for (let i = 0; i < memberCount; i++) {
      const figure = new Graphics();
      const fx = -50 - i * 20;

      // Body (simple colored rectangle)
      const colors = [0x4466aa, 0xaa4444, 0x44aa44, 0xaa8844];
      figure.rect(fx - 5, -24, 10, 18);
      figure.fill(colors[i % colors.length]);

      // Head
      figure.circle(fx, -30, 6);
      figure.fill(0xddbbaa);

      // Legs
      figure.rect(fx - 4, -6, 3, 8);
      figure.fill(0x333333);
      figure.rect(fx + 1, -6, 3, 8);
      figure.fill(0x333333);

      this._caravanContainer.addChild(figure);
    }

    // Position caravan on the path
    this._caravanContainer.x = this._width * 0.35;
    this._caravanContainer.y = pathY;

    this.container.addChild(this._caravanContainer);
  }

  // ── HUD Setup (HTML/CSS) ────────────────────────────

  _buildHUD() {
    const uiRoot = document.getElementById('ui-root');
    if (!uiRoot) return;

    this._hudEl = document.createElement('div');
    this._hudEl.id = 'travel-hud';
    this._hudEl.className = 'travel-hud';
    this._hudEl.setAttribute('data-scene', 'WorldTravel');

    // Top-left: Region info
    const regionInfo = document.createElement('div');
    regionInfo.className = 'travel-hud-region';
    regionInfo.id = 'travel-region-info';
    regionInfo.innerHTML = `
      <div class="travel-region-name" id="travel-region-name">Loading...</div>
      <div class="travel-region-level" id="travel-region-level"></div>
    `;
    this._hudEl.appendChild(regionInfo);

    // Top-right: Day/time
    const timeInfo = document.createElement('div');
    timeInfo.className = 'travel-hud-time';
    timeInfo.id = 'travel-time-info';
    timeInfo.innerHTML = `
      <div class="travel-day" id="travel-day">Day 1</div>
      <div class="travel-time-of-day" id="travel-time-of-day">Morning</div>
    `;
    this._hudEl.appendChild(timeInfo);

    // Bottom bar
    const bottomBar = document.createElement('div');
    bottomBar.className = 'travel-hud-bottom';

    // Speed button
    const speedBtn = document.createElement('button');
    speedBtn.className = 'travel-speed-btn';
    speedBtn.id = 'travel-speed-btn';
    speedBtn.setAttribute('data-focusable', 'true');
    speedBtn.textContent = 'Normal';
    speedBtn.addEventListener('click', () => {
      const newSpeed = travelSystem.toggleSpeed();
      speedBtn.textContent = newSpeed === 1 ? 'Normal' : 'Fast (x2)';
    });
    bottomBar.appendChild(speedBtn);

    // Party status summary
    const partyStatus = document.createElement('div');
    partyStatus.className = 'travel-party-status';
    partyStatus.id = 'travel-party-status';
    partyStatus.textContent = '';
    bottomBar.appendChild(partyStatus);

    this._hudEl.appendChild(bottomBar);

    uiRoot.appendChild(this._hudEl);
  }

  _updateHUD() {
    const region = travelSystem.currentRegion;
    if (!region) return;

    // Region name
    const regionNameEl = document.getElementById('travel-region-name');
    if (regionNameEl) regionNameEl.textContent = region.name;

    // Region level
    const regionLevelEl = document.getElementById('travel-region-level');
    if (regionLevelEl) regionLevelEl.textContent = `Lv ${region.levelRange[0]}-${region.levelRange[1]}`;

    // Day
    const dayEl = document.getElementById('travel-day');
    if (dayEl) dayEl.textContent = `Day ${travelSystem.day}`;

    // Time of day
    const todEl = document.getElementById('travel-time-of-day');
    if (todEl) todEl.textContent = travelSystem.getTimeOfDay();

    // Party status
    const partyEl = document.getElementById('travel-party-status');
    if (partyEl && travelSystem.party) {
      const members = travelSystem.party.members;
      const summaries = members.map(m => `${m.name}: ${m.hp}/${m.maxHp} HP`);
      partyEl.textContent = summaries.join('  |  ');
    }

    // Speed button
    const speedBtn = document.getElementById('travel-speed-btn');
    if (speedBtn) {
      speedBtn.textContent = travelSystem.speedMultiplier === 1 ? 'Normal' : 'Fast (x2)';
    }
  }

  // ── Dialog System ───────────────────────────────────

  _showRegionTransitionDialog(connections) {
    this._dismissDialog();

    const uiRoot = document.getElementById('ui-root');
    if (!uiRoot) return;

    const region = travelSystem.currentRegion;

    this._dialogEl = document.createElement('div');
    this._dialogEl.className = 'travel-dialog';
    this._dialogEl.id = 'travel-region-dialog';
    this._dialogEl.setAttribute('role', 'dialog');
    this._dialogEl.setAttribute('aria-label', 'Region Transition');

    const title = document.createElement('h3');
    title.className = 'travel-dialog-title';
    title.textContent = `Leaving ${region ? region.name : 'Unknown'}`;
    this._dialogEl.appendChild(title);

    const desc = document.createElement('p');
    desc.className = 'travel-dialog-desc';
    desc.textContent = 'Choose your next destination:';
    this._dialogEl.appendChild(desc);

    const btnContainer = document.createElement('div');
    btnContainer.className = 'travel-dialog-buttons';

    for (const connId of connections) {
      const connRegion = dataStore.getById('regions', connId);
      if (!connRegion) continue;

      const btn = document.createElement('button');
      btn.className = 'travel-dialog-btn';
      btn.setAttribute('data-focusable', 'true');
      btn.setAttribute('data-region-id', connId);
      btn.innerHTML = `
        <span class="travel-dialog-btn-name">${connRegion.name}</span>
        <span class="travel-dialog-btn-level">Lv ${connRegion.levelRange[0]}-${connRegion.levelRange[1]}</span>
      `;
      btn.addEventListener('click', () => {
        this._dismissDialog();
        travelSystem.changeRegion(connId);
        travelSystem.resume();
        // Update palette for new biome
        const newRegion = travelSystem.currentRegion;
        if (newRegion) {
          this._palette = BIOME_PALETTES[newRegion.biome] || DEFAULT_PALETTE;
          this._rebuildParallax();
        }
        this._updateHUD();
      });
      btnContainer.appendChild(btn);
    }

    this._dialogEl.appendChild(btnContainer);

    // Stay button
    const stayBtn = document.createElement('button');
    stayBtn.className = 'travel-dialog-btn travel-dialog-btn-cancel';
    stayBtn.setAttribute('data-focusable', 'true');
    stayBtn.textContent = 'Stay in Region';
    stayBtn.addEventListener('click', () => {
      this._dismissDialog();
      travelSystem.position = 0;
      travelSystem.resume();
    });
    btnContainer.appendChild(stayBtn);

    uiRoot.appendChild(this._dialogEl);

    // Push focus group
    focusManager.pushGroup('region-transition', this._dialogEl);
  }

  _showEncounterDialog(encounter) {
    this._dismissDialog();

    const uiRoot = document.getElementById('ui-root');
    if (!uiRoot) return;

    this._dialogEl = document.createElement('div');
    this._dialogEl.className = 'travel-dialog';
    this._dialogEl.id = 'travel-encounter-dialog';
    this._dialogEl.setAttribute('role', 'dialog');
    this._dialogEl.setAttribute('aria-label', 'Encounter');

    const title = document.createElement('h3');
    title.className = 'travel-dialog-title';
    title.textContent = 'Encounter!';
    this._dialogEl.appendChild(title);

    // Describe the encounter
    const desc = document.createElement('p');
    desc.className = 'travel-dialog-desc';

    if (encounter.enemies && encounter.enemies.length > 0) {
      // Group enemies by name
      const counts = {};
      for (const e of encounter.enemies) {
        counts[e.name] = (counts[e.name] || 0) + 1;
      }
      const parts = Object.entries(counts).map(([name, count]) =>
        count > 1 ? `${name} x${count}` : name
      );
      desc.textContent = `You encounter: ${parts.join(', ')}!`;
    } else {
      desc.textContent = 'You encounter something in the distance...';
    }
    this._dialogEl.appendChild(desc);

    const btnContainer = document.createElement('div');
    btnContainer.className = 'travel-dialog-buttons';

    // Fight button (placeholder)
    const fightBtn = document.createElement('button');
    fightBtn.className = 'travel-dialog-btn travel-dialog-btn-fight';
    fightBtn.setAttribute('data-focusable', 'true');
    fightBtn.textContent = 'Fight';
    fightBtn.addEventListener('click', () => {
      this._dismissDialog();
      travelSystem.resume();
      debugLog.info('WorldTravel: Fight initiated (combat not yet implemented)');
    });
    btnContainer.appendChild(fightBtn);

    // Flee button
    const fleeBtn = document.createElement('button');
    fleeBtn.className = 'travel-dialog-btn travel-dialog-btn-cancel';
    fleeBtn.setAttribute('data-focusable', 'true');
    fleeBtn.textContent = 'Flee';
    fleeBtn.addEventListener('click', () => {
      this._dismissDialog();
      travelSystem.resume();
      debugLog.info('WorldTravel: Fled from encounter');
    });
    btnContainer.appendChild(fleeBtn);

    this._dialogEl.appendChild(btnContainer);

    uiRoot.appendChild(this._dialogEl);

    // Push focus group
    focusManager.pushGroup('encounter', this._dialogEl);
  }

  _dismissDialog() {
    if (this._dialogEl) {
      // Pop focus group if it's for one of our dialogs
      const topGroup = focusManager._currentGroup?.call
        ? focusManager._currentGroup()
        : null;
      if (topGroup && (topGroup.name === 'region-transition' || topGroup.name === 'encounter')) {
        focusManager.popGroup();
      }

      if (this._dialogEl.parentNode) {
        this._dialogEl.parentNode.removeChild(this._dialogEl);
      }
      this._dialogEl = null;
    }
  }

  // ── Event Subscriptions ─────────────────────────────

  _subscribeEvents() {
    this._eventHandlers.onNode = () => {
      this._updateHUD();
    };
    this._eventHandlers.onDayAdvance = () => {
      this._updateHUD();
    };
    this._eventHandlers.onEncounter = (encounter) => {
      this._showEncounterDialog(encounter);
    };
    this._eventHandlers.onRegionEdge = (data) => {
      this._showRegionTransitionDialog(data.connections);
    };
    this._eventHandlers.onRegionChange = () => {
      this._updateHUD();
    };
    this._eventHandlers.onTimeChanged = () => {
      this._updateHUD();
    };

    eventBus.on('travel:node', this._eventHandlers.onNode);
    eventBus.on('travel:day-advance', this._eventHandlers.onDayAdvance);
    eventBus.on('travel:encounter', this._eventHandlers.onEncounter);
    eventBus.on('travel:region-edge', this._eventHandlers.onRegionEdge);
    eventBus.on('travel:region-change', this._eventHandlers.onRegionChange);
    eventBus.on('travel:time-changed', this._eventHandlers.onTimeChanged);
  }

  _unsubscribeEvents() {
    if (this._eventHandlers.onNode) {
      eventBus.off('travel:node', this._eventHandlers.onNode);
    }
    if (this._eventHandlers.onDayAdvance) {
      eventBus.off('travel:day-advance', this._eventHandlers.onDayAdvance);
    }
    if (this._eventHandlers.onEncounter) {
      eventBus.off('travel:encounter', this._eventHandlers.onEncounter);
    }
    if (this._eventHandlers.onRegionEdge) {
      eventBus.off('travel:region-edge', this._eventHandlers.onRegionEdge);
    }
    if (this._eventHandlers.onRegionChange) {
      eventBus.off('travel:region-change', this._eventHandlers.onRegionChange);
    }
    if (this._eventHandlers.onTimeChanged) {
      eventBus.off('travel:time-changed', this._eventHandlers.onTimeChanged);
    }
    this._eventHandlers = {};
  }

  // ── Debug Commands ──────────────────────────────────

  _registerDebugCommands() {
    const dc = window.__debug?.console;
    if (!dc) return;

    // Override teleport command with working version
    dc.registerCommand('teleport', (args) => {
      const regionId = args[0];
      if (!regionId) return 'Usage: teleport <region_id>';

      const region = dataStore.getById('regions', regionId);
      if (!region) return `Region not found: ${regionId}`;

      travelSystem.changeRegion(regionId);
      travelSystem.resume();

      // Update visuals
      this._palette = BIOME_PALETTES[region.biome] || DEFAULT_PALETTE;
      this._rebuildParallax();
      this._updateHUD();

      return `Teleported to ${region.name}`;
    }, 'Teleport to region: teleport <region_id>');

    // Override settime command with working version
    dc.registerCommand('settime', (args) => {
      const nodeIdx = parseInt(args[0], 10);
      if (isNaN(nodeIdx)) return 'Usage: settime <0-4> (0=Morning, 1-2=Afternoon, 3=Evening, 4=Night)';

      travelSystem.setTimeOfDay(nodeIdx);
      this._updateHUD();

      return `Time set to ${travelSystem.getTimeOfDay()} (node ${travelSystem.nodeInDay})`;
    }, 'Set time of day: settime <0-4>');

    // Trigger encounter
    dc.registerCommand('triggerencounter', () => {
      const encounter = travelSystem.triggerEncounter();
      return `Encounter triggered: ${encounter.enemies?.map(e => e.name).join(', ') || 'empty'}`;
    }, 'Trigger a random encounter');

    // Force region transition
    dc.registerCommand('triggerregion', () => {
      const region = travelSystem.currentRegion;
      if (!region) return 'No current region';

      travelSystem.paused = true;
      this._showRegionTransitionDialog(region.connections);
      return `Region transition dialog shown. Connections: ${region.connections.join(', ')}`;
    }, 'Show region transition dialog');

    // Expose on window.__debug.commands
    if (window.__debug) {
      window.__debug.commands.teleport = (args) => {
        const regionId = typeof args === 'string' ? args : args[0];
        travelSystem.changeRegion(regionId);
        travelSystem.resume();
        this._palette = BIOME_PALETTES[travelSystem.currentRegion?.biome] || DEFAULT_PALETTE;
        this._rebuildParallax();
        this._updateHUD();
      };
      window.__debug.commands.settime = (args) => {
        const nodeIdx = typeof args === 'number' ? args : parseInt(args[0] || args, 10);
        travelSystem.setTimeOfDay(nodeIdx);
        this._updateHUD();
      };
      window.__debug.commands.triggerencounter = () => {
        return travelSystem.triggerEncounter();
      };
      window.__debug.commands.triggerregion = () => {
        const region = travelSystem.currentRegion;
        if (region) {
          travelSystem.paused = true;
          this._showRegionTransitionDialog(region.connections);
        }
      };
    }
  }

  // ── Rebuild ─────────────────────────────────────────

  _rebuildParallax() {
    // Remove old parallax
    if (this._parallax) {
      if (this._parallax.root.parent) {
        this.container.removeChild(this._parallax.root);
      }
      this._parallax.destroy();
      this._parallax = null;
    }

    // Remove and re-add caravan so it stays on top
    if (this._caravanContainer && this._caravanContainer.parent) {
      this.container.removeChild(this._caravanContainer);
    }

    this._buildParallax();

    // Re-add caravan on top
    if (this._caravanContainer) {
      this.container.addChild(this._caravanContainer);
    }

    // Reset camera
    this._cameraX = travelSystem.position * 100;
  }

  // ── Update Loop ─────────────────────────────────────

  update(dt) {
    // Check for shift key to toggle fast speed while held
    if (inputManager.isPressed('Shift') || inputManager.isPressed('ShiftLeft') || inputManager.isPressed('ShiftRight')) {
      if (travelSystem.speedMultiplier !== 2) {
        travelSystem.setSpeed(2);
        const speedBtn = document.getElementById('travel-speed-btn');
        if (speedBtn) speedBtn.textContent = 'Fast (x2)';
      }
    } else if (travelSystem.speedMultiplier === 2) {
      // Only reset to normal if speed was set by shift (not by button)
      // We check if shift was just released
    }

    // Advance travel
    travelSystem.advance(dt);

    // Update camera based on travel position
    this._cameraX = travelSystem.position * 100;

    // Update parallax
    if (this._parallax) {
      this._parallax.update(this._cameraX);

      // Update day/night tint
      const tint = travelSystem.getDayNightTint();
      this._parallax.lerpTint(tint.color, tint.alpha, 2.0, dt);
    }

    // Simple caravan bob animation
    if (this._caravanContainer && travelSystem.traveling && !travelSystem.paused) {
      this._caravanContainer.y += Math.sin(performance.now() * 0.004) * 0.15;
    }
  }

  // ── Resize ──────────────────────────────────────────

  resize(w, h) {
    this._width = w;
    this._height = h;

    if (this._parallax) {
      this._parallax.resize(w, h);
    }

    // Reposition caravan
    if (this._caravanContainer) {
      const groundY = h * (1 - GROUND_FRACTION);
      const pathY = groundY + (h - groundY) * 0.35;
      this._caravanContainer.x = w * 0.35;
      this._caravanContainer.y = pathY;
    }
  }
}
